package unverified;

import org.junit.jupiter.api.Test;

import java.nio.charset.StandardCharsets;
import java.util.Base64;
import java.util.List;
import java.util.concurrent.TimeUnit;

import static org.junit.jupiter.api.Assertions.assertEquals;
import static org.junit.jupiter.api.Assertions.assertNotEquals;
import static org.junit.jupiter.api.Assertions.assertTrue;
import static unverified.ClonePairAliasAwareInvocationTestSupport.*;

class ClonePair9348DifferenceFindingTest {

    /**
     * Generated by Codex (GPT-5).
     * separating case: novel_0_1 ["Double.POSITIVE_INFINITY"]
     *
     * Runs each side in a fresh JVM so timeout-based behavior is not affected by
     * daemon threads left behind by other timeout-focused tests.
     */
    @Test
    void methodsDisagreeOnGeneratedInput() throws Exception {
        ProbeResult method1Outcome = runProbe("method1");
        ProbeResult method2Outcome = runProbe("method2");

        assertCoreResult(
            method1Outcome,
            "TIMEOUT",
            null,
            null,
            "java.lang.Object[][Double(Infinity)]",
            "<snapshot-skipped-after-timeout>"
        );
        assertCoreResult(
            method2Outcome,
            "OK",
            "Double(NaN)",
            null,
            "java.lang.Object[][Double(Infinity)]",
            "java.lang.Object[][Double(Infinity)]"
        );
        assertTextEquals("stdout", "", method1Outcome.stdout);
        assertTextEquals("stdout", "", method2Outcome.stdout);
        assertTextEquals("stderr", "", method1Outcome.stderr);
        assertTextEquals("stderr", "", method2Outcome.stderr);
        assertNotEquals(method1Outcome.status, method2Outcome.status);
    }

    private static ProbeResult runProbe(String methodName) throws Exception {
        Process process = new ProcessBuilder(
            javaCommand(),
            "-cp",
            System.getProperty("java.class.path"),
            "unverified.ClonePair9348DifferenceFindingTest$TimeoutProbe",
            methodName
        ).start();

        boolean finished = process.waitFor(5L, TimeUnit.SECONDS);
        if (!finished) {
            process.destroyForcibly();
            throw new AssertionError("timeout probe did not finish");
        }

        String stdout = new String(process.getInputStream().readAllBytes(), StandardCharsets.UTF_8).trim();
        String stderr = new String(process.getErrorStream().readAllBytes(), StandardCharsets.UTF_8).trim();
        assertEquals(0, process.exitValue(), stderr);
        String[] parts = stdout.split("\t", -1);
        assertEquals(7, parts.length, stdout);
        return new ProbeResult(
            parts[0],
            decode(parts[1]),
            decode(parts[2]),
            decode(parts[3]),
            decode(parts[4]),
            decode(parts[5]),
            decode(parts[6])
        );
    }

    private static String javaCommand() {
        return PathUtil.javaExecutable();
    }

    private static String decode(String value) {
        if ("-".equals(value)) {
            return null;
        }
        return new String(Base64.getDecoder().decode(value), StandardCharsets.UTF_8);
    }

    private static void assertCoreResult(
        ProbeResult actual,
        String expectedStatus,
        String expectedValueSnapshot,
        String expectedExceptionClass,
        String expectedOriginalInputsSnapshot,
        String expectedInputAfterSnapshot
    ) {
        assertEquals(expectedStatus, actual.status);
        assertEquals(expectedValueSnapshot, actual.valueSnapshot);
        assertEquals(expectedExceptionClass, actual.exceptionClass);
        assertEquals(expectedOriginalInputsSnapshot, actual.originalInputsSnapshot);
        assertEquals(expectedInputAfterSnapshot, actual.inputAfterSnapshot);
    }

    private static Object[] buildMethod1Inputs() {
        return new Object[]{Double.POSITIVE_INFINITY};
    }

    private static Object[] buildMethod2Inputs() {
        return new Object[]{Double.POSITIVE_INFINITY};
    }

    private record ProbeResult(
        String status,
        String valueSnapshot,
        String exceptionClass,
        String stdout,
        String stderr,
        String originalInputsSnapshot,
        String inputAfterSnapshot
    ) {}

    static final class TimeoutProbe {

        public static void main(String[] args) {
            ClonePair9348 subject = new ClonePair9348();
            InvocationOutcome outcome;
            if (args.length != 1) {
                throw new IllegalArgumentException("expected method selector");
            }
            if ("method1".equals(args[0])) {
                outcome = captureWithTimeout(values -> subject.method1(((Double) values[0]).doubleValue()), 1000L, buildMethod1Inputs());
            } else if ("method2".equals(args[0])) {
                outcome = captureWithTimeout(values -> subject.method2(((Double) values[0]).doubleValue()), 1000L, buildMethod2Inputs());
            } else {
                throw new IllegalArgumentException(args[0]);
            }
            System.out.print(format(outcome));
        }

        private static String format(InvocationOutcome outcome) {
            return String.join(
                "\t",
                List.of(
                    outcome.status,
                    encode(outcome.valueSnapshot),
                    encode(outcome.exceptionClass),
                    encode(outcome.stdout),
                    encode(outcome.stderr),
                    encode(outcome.originalInputsSnapshot),
                    encode(outcome.inputAfterSnapshot)
                )
            );
        }

        private static String encode(String value) {
            if (value == null) {
                return "-";
            }
            return Base64.getEncoder().encodeToString(value.getBytes(StandardCharsets.UTF_8));
        }
    }

    private static final class PathUtil {

        private static String javaExecutable() {
            String home = System.getProperty("java.home");
            String suffix = System.getProperty("os.name", "").toLowerCase().contains("win") ? "\\bin\\java.exe" : "/bin/java";
            return home + suffix;
        }
    }
}
